export async function main(_ctx, _input) {
  const log = [];
  async function f() {
    try { log.push('try'); await Promise.resolve(); log.push('after-await'); return 'r'; }
    finally { log.push('finally'); }
  }
  log.push('start');
  Promise.resolve().then(() => log.push('microtask-A'));
  const r = await f();
  Promise.resolve().then(() => log.push('microtask-B'));
  await Promise.resolve();
  log.push('end');
  return { ok: true, value: { log, r } };
}
